function bytesToBuffer(bytes) {
  if (!Array.isArray(bytes)) throw new TypeError('Expected an array of byte values');
  const buf = Buffer.allocUnsafe(bytes.length);
  for (let i = 0; i < bytes.length; i++) {
    const n = bytes[i];
    if (!Number.isInteger(n) || n < 0 || n > 255) {
      throw new RangeError(`Invalid byte at index ${i}: ${n}`);
    }
    buf[i] = n;
  }
  return buf;
}

