const tls = require('tls');
const net = require('net');

function createTlsStreamPair(options = {}) {
  const {
    serverOptions = {},
    clientOptions = {},
    serverHost = '127.0.0.1',
    serverPort = 0,
    serverSni = undefined,
    clientSni = undefined,
  } = options;

  const server = net.createServer();
  return new Promise((resolve, reject) => {
    server.on('error', reject);
    server.listen(serverPort, serverHost, () => {
      const { port } = server.address();

      const clearServer = new net.Socket();
      const clearClient = new net.Socket();

      clearServer.connect(port, serverHost);
      clearClient.connect(port, serverHost);

      const tlsServer = tls.connect({
        socket: clearServer,
        servername: serverSni,
        ...serverOptions,
      });

      const tlsClient = tls.connect({
        socket: clearClient,
        servername: clientSni,
        ...clientOptions,
      });

      let done = false;
      const finish = () => {
        if (done) return;
        done = true;
        server.close();
        resolve({
          encrypted: { server: tlsServer, client: tlsClient },
          cleartext: { server: clearServer, client: clearClient },
        });
      };

      let pending = 2;
      const onReady = () => {
        if (--pending === 0) finish();
      };

      tlsServer.once('secureConnect', onReady);
      tlsClient.once('secureConnect', onReady);

      const onErr = (e) => {
        if (done) return;
        done = true;
        server.close();
        reject(e);
      };

      tlsServer.once('error', onErr);
      tlsClient.once('error', onErr);
      clearServer.once('error', onErr);
      clearClient.once('error', onErr);
    });
  });
}

