function evaluateExpression(expr) {
  if (typeof expr !== "string") throw new TypeError("Expression must be a string");
  const s = expr.replace(/\s+/g, "");
  if (!s) throw new Error("Empty expression");

  const tokens = [];
  const re = /(\d+(?:\.\d+)?|[()+\-*/^])/g;
  let m;
  while ((m = re.exec(s)) !== null) tokens.push(m[1]);
  if (tokens.join("") !== s) throw new Error("Invalid characters in expression");

  const prec = { "+": 1, "-": 1, "*": 2, "/": 2, "^": 3 };
  const rightAssoc = new Set(["^"]);
  const output = [];
  const ops = [];

  for (const t of tokens) {
    if (/^\d/.test(t)) {
      output.push(Number(t));
    } else if (t === "(") {
      ops.push(t);
    } else if (t === ")") {
      while (ops.length && ops[ops.length - 1] !== "(") output.push(ops.pop());
      if (!ops.length) throw new Error("Mismatched parentheses");
      ops.pop();
    } else {
      // Handle unary +/-
      if ((t === "+" || t === "-") && (output.length === 0 && ops.length === 0 || ["(", "+", "-", "*", "/", "^"].includes(ops[ops.length - 1] ?? "("))) {
        output.push(0);
      }
      while (ops.length) {
        const top = ops[ops.length - 1];
        if (top === "(") break;
        const pTop = prec[top], pT = prec[t];
        if (pTop > pT || (pTop === pT && !rightAssoc.has(t))) output.push(ops.pop());
        else break;
      }
      ops.push(t);
    }
  }
  while (ops.length) {
    const op = ops.pop();
    if (op === "(") throw new Error("Mismatched parentheses");
    output.push(op);
  }

  const stack = [];
  for (const item of output) {
    if (typeof item === "number") stack.push(item);
    else {
      const b = stack.pop(), a = stack.pop();
      if (a === undefined || b === undefined) throw new Error("Invalid expression");
      switch (item) {
        case "+": stack.push(a + b); break;
        case "-": stack.push(a - b); break;
        case "*": stack.push(a * b); break;
        case "/": stack.push(a / b); break;
        case "^": stack.push(a ** b); break;
        default: throw new Error("Unknown operator");
      }
    }
  }
  if (stack.length !== 1) throw new Error("Invalid expression");
  const result = stack[0];
  if (!Number.isFinite(result)) throw new Error("Result is not finite");
  return result;
}
