const tls = require('node:tls');
const { Duplex } = require('node:stream');

function createSecureTLSPair(options = {}) {
  const secureContext = tls.createSecureContext(options);
  const encrypted = new Duplex({
    write(chunk, enc, cb) { tlsSocket.push(chunk); cb(); },
    read() {}
  });

  const tlsSocket = new tls.TLSSocket(encrypted, {
    isServer: !!options.isServer,
    secureContext,
    requestCert: !!options.requestCert,
    rejectUnauthorized: options.rejectUnauthorized !== false,
    ALPNProtocols: options.ALPNProtocols,
    SNICallback: options.SNICallback,
    server: options.server,
    session: options.session
  });

  encrypted.on('finish', () => tlsSocket.push(null));
  tlsSocket.on('data', (chunk) => cleartext.push(chunk));
  tlsSocket.on('end', () => cleartext.push(null));
  tlsSocket.on('error', (err) => {
    encrypted.destroy(err);
    cleartext.destroy(err);
  });

  const cleartext = new Duplex({
    write(chunk, enc, cb) { tlsSocket.write(chunk, enc, cb); },
    read() {}
  });

  cleartext.on('finish', () => tlsSocket.end());

  return { encrypted, cleartext, tlsSocket };
}

