function parseTlsSubject(subject) {
  if (subject == null) return {};
  let s = String(subject).trim();
  if (!s) return {};
  if (s.startsWith('/')) s = s.slice(1);

  const out = {};
  let key = '', val = '', inKey = true, esc = false;

  const push = () => {
    if (!key) return;
    const k = key.trim();
    const v = val.trim();
    if (Object.prototype.hasOwnProperty.call(out, k)) {
      out[k] = Array.isArray(out[k]) ? (out[k].push(v), out[k]) : [out[k], v];
    } else {
      out[k] = v;
    }
    key = '';
    val = '';
    inKey = true;
  };

  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (esc) {
      (inKey ? key : val) += ch;
      esc = false;
    } else if (ch === '\\') {
      esc = true;
    } else if (inKey && ch === '=') {
      inKey = false;
    } else if (!inKey && ch === '/') {
      push();
    } else {
      (inKey ? key : val) += ch;
    }
  }
  push();
  return out;
}

