const evaluateExpression = (expression) => {
  const tokens = expression.match(/\d*\.?\d+|[()+\-*/]/g);
  if (!tokens) throw new Error('Invalid expression');

  let i = 0;
  const peek = () => tokens[i];
  const next = () => tokens[i++];

  const parseFactor = () => {
    if (peek() === '+') return next(), parseFactor();
    if (peek() === '-') return next(), -parseFactor();
    if (peek() === '(') {
      next();
      const value = parseExpression();
      if (next() !== ')') throw new Error('Mismatched parentheses');
      return value;
    }
    const token = next();
    if (!token || !/^\d*\.?\d+$/.test(token)) throw new Error('Invalid token');
    return Number(token);
  };

  const parseTerm = () => {
    let value = parseFactor();
    while (peek() === '*' || peek() === '/') {
      const op = next();
      const rhs = parseFactor();
      value = op === '*' ? value * rhs : value / rhs;
    }
    return value;
  };

  const parseExpression = () => {
    let value = parseTerm();
    while (peek() === '+' || peek() === '-') {
      const op = next();
      const rhs = parseTerm();
      value = op === '+' ? value + rhs : value - rhs;
    }
    return value;
  };

  const result = parseExpression();
  if (i !== tokens.length) throw new Error('Invalid expression');
  return result;
};
