import * as tls from 'tls';
import * as fs from 'fs';
import * as net from 'net';

export function createSecureTLSStreamPair() {
  // Create a pair of connected sockets
  const { socket1, socket2 } = net.createSocketPair();

  // Read certificate and key files
  const cert = fs.readFileSync('server.crt', 'utf8');
  const key = fs.readFileSync('server.key', 'utf8');

  // Create TLS server options
  const tlsOptions = {
    cert: cert,
    key: key,
    isServer: true
  };

  // Create encrypted TLS stream
  const encryptedStream = tls.connect({
    socket: socket1,
    ...tlsOptions
  });

  // Create cleartext stream from the other socket
  const cleartextStream = socket2;

  return {
    encryptedStream,
    cleartextStream
  };
}

// Example usage
