  constructor(props) {
    super(props);
    this.state = {
      scrollPosition: 0,
      previousScrollPosition: 0,
    };
  }

  getSnapshotBeforeUpdate(prevProps, prevState) {
    // Record scroll position before update
    const scrollPosition = window.scrollY || document.documentElement.scrollTop;
