const tls = require('tls');
const { Duplex } = require('stream');

function createSecurePair(credentials, isServer, requestCert, rejectUnauthorized) {
  const options = {
    ...credentials,
    isServer: !!isServer,
    requestCert: !!requestCert,
    rejectUnauthorized: rejectUnauthorized !== false,
  };

  const encryptedDuplex = new Duplex({
    read() {},
    write(chunk, encoding, callback) {
      tlsSocket.push(chunk);
      callback();
    },
  });

  const tlsSocket = new tls.TLSSocket(encryptedDuplex, options);

  const pair = {
    encrypted: encryptedDuplex,
    cleartext: tlsSocket,
    on(event, listener) {
      tlsSocket.on(event, listener);
      return this;
    },
  };

  tlsSocket.on('secure', () => {
    pair.cleartext.authorized = tlsSocket.authorized;
    pair.cleartext.authorizationError = tlsSocket.authorizationError;
  });

  return pair;
}

module.exports = createSecurePair;
