// helper.js
export function transformValue(value) {
  if (typeof value === 'string') {
    return value.trim().toUpperCase();
  }
  if (typeof value === 'number') {
    return value * 2;
  }
  return value;
}

// main.js
import { transformValue } from './helper.js';

const inputs = ['  hello world  ', 42, '  javascript  ', 7];

const results = inputs.map(transformValue);

console.log(results);
// ['HELLO WORLD', 84, 'JAVASCRIPT', 14]

